import React, { createContext, useContext, useState, useEffect } from 'react';

const CartContext = createContext();

export const CartProvider = ({ children }) => {
    const [cart, setCart] = useState(() => {
        // Recuperamos el carrito guardado para no perder datos al recargar
        const savedCart = localStorage.getItem('cart_ofertas');
        return savedCart ? JSON.parse(savedCart) : [];
    });

    useEffect(() => {
        localStorage.setItem('cart_ofertas', JSON.stringify(cart));
    }, [cart]);

    const addToCart = (producto) => {
        setCart((prevCart) => {
            const itemExists = prevCart.find((item) => item._id === producto._id);
            if (itemExists) {
                return prevCart.map((item) =>
                    item._id === producto._id 
                        ? { ...item, cantidad: item.cantidad + 1 } 
                        : item
                );
            }
            // Guardamos el producto con la info del local incluida
            return [...prevCart, { ...producto, cantidad: 1 }];
        });
    };

    const removeFromCart = (id) => {
        setCart((prevCart) => prevCart.filter((item) => item._id !== id));
    };

    const updateQuantity = (id, newQty) => {
        if (newQty < 1) return;
        setCart((prevCart) =>
            prevCart.map((item) =>
                item._id === id ? { ...item, cantidad: newQty } : item
            )
        );
    };

    const clearCart = () => setCart([]);

    const totalItems = cart.reduce((acc, item) => acc + item.cantidad, 0);
    const totalPrice = cart.reduce((acc, item) => acc + (item.precioNuevo * item.cantidad), 0);

    return (
        <CartContext.Provider value={{ 
            cart, 
            addToCart, 
            removeFromCart, 
            updateQuantity,
            clearCart, 
            totalItems, 
            totalPrice 
        }}>
            {children}
        </CartContext.Provider>
    );
};

export const useCart = () => useContext(CartContext);
